const output = $input.first().json.output;

let action;

try {
  // Try parsing tool calls (email, calendar, tasks, etc.)
  action = JSON.parse(output);
} catch (e) {
  // Not JSON → it's a normal chat response
  return [
    {
      json: {
        action: "chat",
        output: output,
        provider_token: $input.first().json.provider_token,
      },
    },
  ];
}

// If parsing succeeded, attach the provider token
action.provider_token = $input.first().json.provider_token;

return [
  {
    json: action,
  },
];

const email =
`To: ${$json.to}
Subject: ${$json.subject}
Content-Type: text/plain; charset="UTF-8"

${$json.body}`;

const raw = Buffer.from(email)
  .toString("base64")
  .replace(/\+/g, "-")
  .replace(/\//g, "_")
  .replace(/=+$/, "");

return [{
  json: {
    raw,
    provider_token: $json.provider_token,

    // Keep these so later nodes can use them
    to: $json.to,
    subject: $json.subject,
    body: $json.body
  }
}];

return items.map(item => {
  const headers = item.json.payload.headers;

  const getHeader = (name) => {
    const h = headers.find(x => x.name === name);
    return h ? h.value : "";
  };

  return {
    json: {
      from: getHeader("From"),
      subject: getHeader("Subject"),
      date: getHeader("Date"),
      snippet: item.json.snippet,
    },
  };
});

const event = $input.first().json;

return [
  {
    json: {
      title: event.summary || "Untitled Event",
      start: event.start?.dateTime || event.start?.date,
      end: event.end?.dateTime || event.end?.date,
      location: event.location || "",
      description: event.description || "",
      link: event.htmlLink || ""
    }
  }
];

const task = $json;

return {
  json: {
    id: task.id,
    title: task.title,
    status: task.status,
    updated: task.updated,
    link: task.webViewLink
  }
};

function normalize(text) {
  return (text || "")
    .toLowerCase()
    .trim();
}

const requestedTitle = $("Switch").first().json.title;
const task = $json;

return {
  json: {
    id: task.id,
    title: task.title,
    provider_token: $("Switch").first().json.provider_token,
    title_match:
      normalize(task.title) === normalize(requestedTitle)
  }
};

const targetTitle = $('Code in JavaScript').first().json.title.toLowerCase();

const events = $json.items || [];

const event = events.find(e =>
  e.summary &&
  e.summary.toLowerCase().includes(targetTitle)
);

if (!event) {
  return [
    {
      json: {
        found: false,
        message: "No matching calendar event found."
      }
    }
  ];
}

return [
  {
    json: {
      found: true,
      eventId: event.id,
      title: event.summary,
      provider_token: $('Code in JavaScript').first().json.provider_token
    }
  }
];
